<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --channels</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ttbar </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\</span></span>
