<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --objects</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> particles,tracker_hits,calo_hits,tracks </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\</span></span>
